INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00377', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '要作好一個稱職的警察首長，根據學者Mintzberg及Katz之看法，有三種知識是重要的， 下列何者屬之？', '["概念知識、人際知識及技術知識", "概念知識、專業知識及執行知識", "核心知識、人際知識及科技知識", "法律知識、行政知識及技術知識"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00378', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '教育與訓練二者概念接近，常合併使用，但實有不同，有關二者區別之敘述，下列何者正確？', '["教育的功能在促進個人能力於工作上的應用，訓練則是為發展人才", "教育的目的在適應一般需要，訓練的目的則在適應特殊需要", "教育的應用價值在立即需要，訓練的應用價值為適應一般需要", "教育的內容為專門知識與技能，訓練的內容則為基本知識"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00379', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察人員執行職務應廉潔自持、公正無私及依法行政，並遵守公務員廉政倫理規範規定，下 列敘述何者錯誤？', '["警察人員應依法公正執行職務，以公共利益為依歸，不得假借職務上之權力、方法、機會 圖本人或第三人不正之利益", "警察人員遇有請託關說時，應於1週內簽報其長官並知會政風機構", "正常社交禮俗標準指一般人社交往來，市價不超過新臺幣三千元者。但同一年度來自同一 來源受贈財物以新臺幣一萬元為限", "除因公務需要經報請長官同意，或有其他正當理由者外，不得涉足不妥當之場所"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00380', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察機關基於任務特殊性與執法需要，在公務倫理上必須遵守公務員服務法，有關公務員服 務法之規定，下列敘述何者錯誤？', '["第14條規定，公務員除法令規定外，不得兼任他項公職；其依法令兼職者，不得兼薪", "第5條第1項規定，公務員有絕對保守政府機關（構）機密之義務，對於機密事件，無論 是否主管事務，均不得洩漏；離職後，亦同", "輪班制公務員更換班次時，至少應有連續 11 小時之休息時間。但因應勤（業）務需要或 其他特殊情形，不在此限", "為搶救重大災害、處理緊急或重大突發事件、辦理重大專案業務或辦理季節性、週期性工 作等例外情形，延長辦公時數上限，由總統府、國家安全會議及五院分別定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00381', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '111年6月22日公布施行之公務員服務法第3條，原係規範公務員服從之義務，新法參照 公務人員保障法第 17 條之規範修正，除了可釐清長官與屬員間之責任外，亦展現長官負責 任之領導作為。有關該條增修之敘述，下列何者不正確？', '["公務員有正當理由認為長官命令違法但未有違反刑事法律者，應負報告之義務。受報告之 長官如堅持其命令未違法時，以書面署名再次下達，公務員即應無異議服從，以期命令得 以貫徹執行，惟此時責任係歸屬於長官", "又如長官命令違法而公務員明知卻仍服從執行時，依中華民國刑法第21條第2項但書規 定，公務員尚不得主張阻卻違法，是為適度保障公務員權利，爰明定長官命令違反刑事法 律時，公務員無服從之義務", "所指以書面署名下達之「書面」，鑑於現行電子通訊普及，且易遭盜用或竄改，長官以電 子郵件或通訊軟體等形式下達足資表達命令內容之各種型態者，則不屬之", "依據憲法或法律獨立行使職權之公務員，例如法官、公平交易委員會委員等，渠等於「職 權範圍內」經憲法或法律明定獨立行使職權，當不生服從義務之疑義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00382', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '司法院釋字第785號解釋、公務員服務法、公務人員保障法對於警察人員健康權之意義、性 質、依據及保障範圍，下列敘述何者錯誤？', '["健康權為複合性權利，兼具自由權與社會權性質", "警察人員補休假應於機關規定之補休假期限內補休完畢，補休假期限至多為1年", "警察機關之加班補償，應考量加班之性質、強度、密度、時段等因素，以符合一般社會通 念之合理執行職務對價及保障員警健康權之原則下，予以適當評價，並依加班補償評價之 級距與下限，訂定換算基準，核給加班費、補休假", "警察機關為全年無休服務民眾，應實施輪班、輪休制度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00383', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關我國的警政組織型態與未來發展趨勢，下列敘述何者錯誤？', '["我國傳統的警察組織型態並非金字塔的階梯式組織，而是呈現多處瓶頸的怪葫蘆現象", "梅可望先生主張，我國未來警政發展之主軸與方向，為科技與文化、倫理雙軌並進的永續 經營之願景與策略", "我國憲法第108條至第110條有關警政之設計發展，堅持「政策由中央制定，警衛事項授 權地方」，此原則即是管理科學中探討的「集權的行政，分權的監督」", "民國104年起內政部警政署開始加強雲端網路應用，整合系統發展情資導向的警政治安新 策略，翌年則推動「科技建警、偵防並重」的警政發展方向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00384', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '為了強化國家關鍵基礎設施的防衛，未來警政發展趨勢，下列敘述何者錯誤？', '["內政部部長於112年3月30日指出，政府規劃未來警察將擔負電廠、油庫、水庫及機場 等國家重要基礎設施安全防護工作的任務", "政府為因應防衛國土安全，自113年1月1日起開始實施義務役兵役延長為1年", "國家關鍵基礎設施依功能屬性區分為八大領域：能源、水資源、通訊傳播、交通、金融、 緊急救援與醫院、政府機關及科學園區與工業區的防護，未來將提升安全維護等級", "目前維護電廠、天然氣廠、科學園區等國家關鍵基礎設施的警察機關是保安警察第三總隊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00385', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據「警察勤務條例」規定，下列有關警察勤務區的敘述何者正確？', '["刑事警察得配合警察勤務區劃分責任區", "警察分駐（派出）所為警察勤務基本單位，負責警勤區之規劃、勤務執行及督導", "依自治區域，均以一村里劃設一警察勤務區", "交通警察得配合警察勤務區劃分責任區"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00386', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '無論是現在或在可預見之未來，亦無論警察勤務如何變革，警察勤務之運作上仍脫不了迅速 原理、機動原理、彈性原理及顯見原理。下列敘述何者正確？', '["迅速原理，其基本假設是，警察勤務應為主動先發式的發現問題，而非被動反應式的處理 問題", "顯見原理，即見警率的歸納，亦即警察在執行各項勤務時所展現的外觀作為，包括巡邏、 守望、特勤及刑事警察等勤務", "彈性原理，其基本假設是，警察事故發生的不可預期與時空差異性，因而警察勤務也必須 隨之而變化", "機動原理，其基本假設是，警察人員越早到達犯罪現場，則逮捕犯罪人之機會越大，以及 破案的可能性越高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "5a18fc842c18", "answer_pdf_sha1": "84c4c8847104", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1208", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
